export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:22。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鐘樓的燈死了。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是漸暗。是一刀切斷。所有走廊燈、應急燈、樓層指示燈，在同一秒裡滅掉。黑暗像一桶冷水從頭頂澆下來，把整座鐘樓的內部吞乾淨。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "只剩下雨。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨從鐘樓背面的維修平台灌進來。平台沒有外牆——只有鏽蝕的鐵欄杆和半截擋雨板。風把雨吹成斜的，打在臉上像碎冰。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）停電了。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）22:22。和每一輪一樣。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他蹲在平台角落。背靠鐵欄杆。手裡捏著自己的手機——最後一樣東西。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕亮著。鎖定畫面上的時間顯示 22:22。他把螢幕亮度調到最高，然後把手機塞進背包最外層的夾層裡。拉鏈沒有拉死——留了一指寬的縫。螢幕的光從那道縫裡漏出來，在暴雨裡像一顆在暴雨裡掙扎的心跳。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）手機在背包裡。背包在假人上。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）最後一步了。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他轉頭看了一眼身邊的東西。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑雨衣裹在人形舞台支架上。支架是鋁合金的，不重，但撐起雨衣之後遠看像一個人。背包綁在支架上半部，用尼龍繩繞了三圈，打的是活結——一扯就鬆。旁邊還有兩個裝了沙的器材袋，用來配重。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是電影道具。是校慶舞台組倉庫裡能找到的東西。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越下午就搬好了。黑雨衣、支架、器材袋、沙。全部堆在維修平台角落，蓋一塊帆布。平常沒有人來這裡——鐘樓背面是封閉區，只有維修時才開放，校慶期間更不會有人注意。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）夠了。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不需要騙所有人。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）只需要騙一個人。騙他三十八分鐘。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把背包的最後一圈尼龍繩收緊。手指在雨裡打滑，繞了兩次才打好。雨水順著袖口灌進來，整條手臂都是冰的。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他聽見了腳步聲。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "從平台另一端的維修梯傳來。很急。金屬梯面上踩出叮叮叮的聲響，和雨聲混在一起。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯好了沒有。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越從梯口冒出來。全身濕透。頭髮貼在額頭上。手裡捏著一截尼龍繩的尾端——他從另一側過來，負責在假人推出去的時候從背面拉繩，讓它從平台邊緣翻落。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "好了。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "手機呢。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "在背包裡。亮著。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越看了一眼背包夾層裡漏出來的光。在暴雨裡，那道光很小、很弱，但足以讓遠處的監控捕捉到一個「有人在此」的訊號。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "雨太大。監控拍不清楚。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不需要清楚。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "需要像。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "像一個人。一個穿黑雨衣、背著背包、手機還亮著的人。在22:22的停電裡，在暴雨裡，在監控切線的低畫質畫面裡——像就夠了。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔不會親自來確認。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他會透過監控。透過校安回報。透過林主任。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他會看到——黑雨衣、背包、手機亮光。從鐘樓背面維修平台墜落。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）然後他會判斷——顧言在鐘樓背面。23:00 前不可能再出現。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這就夠了。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:23。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越蹲在平台另一側。尼龍繩繞過欄杆底部，連著假人的支架。他抬頭看了顧言一眼。雨從他額頭上流下來，分不清是雨水還是別的什麼。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯你確定。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "推。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的嘴唇壓緊了。他沒有再問。他點了一下頭——很小的動作，下巴往下再回來——然後他的手收緊了尼龍繩。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站起來。走到假人旁邊。他的手按在支架上。鋁合金的觸感很涼，比雨還涼。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第一章。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我站在鐘樓邊緣。背後有一隻手。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）那隻手推了我。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我掉了下去。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）現在。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）換我推了。", background: Background.Chapter_8_Ch8_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他用盡全力把假人推向平台邊緣。支架在濕滑的鐵板上滑動，發出刺耳的金屬摩擦聲。韓越同時從背面拉繩——假人翻過欄杆。黑雨衣在暴雨裡展開。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "背包跟著翻下去了。手機螢幕的光在墜落中劃出一道短暫的白線。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後是悶響。從下面傳上來。和雨聲混在一起，分不清是什麼。但夠了。在監控畫面裡，在遠處校安的視線裡，在邵叔透過任何一個鏡頭看到的畫面裡——這就是一個人從鐘樓背面墜落。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "對講機裡傳來校安的聲音——模糊的、暴雨裡的回報。鐘樓方向。有人墜落。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有看下去。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他已經轉身了。", background: Background.Chapter_8_Ch8_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:24。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從維修梯往下走。不是跑——跑會踩出聲音。是快走。手扶著欄杆，腳掌先落地再放下腳跟，每一步都壓著聲音。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越在前面。他熟悉這條路——下午搬道具的時候走過兩次。鐘樓背面有一條戶外器材服務走廊，連接維修庭院和舊器材倉，再通到禮堂側台卸貨口。平常上鎖，但今天舞台組搬備用燈架開過一次，韓越知道門沒有重新鎖死。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）服務走廊。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）韓越說過——只能一次。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）一次就夠了。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們從鐘樓底部的側門出來。雨打在身上。和鐘樓裡面比起來，外面的雨反而顯得開闊——至少看得見天空。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越在前面走。他沒有回頭。他的背影在雨裡很瘦，校服外套濕透了貼在肩膀上，脖子上的舞台組通行證在風裡晃。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "器材服務走廊是一條半開放的通道。左邊是禮堂外牆，右邊是鐵皮圍欄。頂上有波浪板遮雨，但雨從側面灌進來，地面還是濕的。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有人。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校慶期間所有人都集中在禮堂和主廣場。這條走廊在禮堂背面，只有舞台組搬器材的時候才會有人走。現在是閉幕前最後三十分鐘，舞台組全在側台待命，沒有人會來這裡。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔現在應該收到了。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）校安回報——鐘樓背面封鎖區有黑雨衣和背包墜落。暴雨積水。暫時無法近距確認。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他會判斷——", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）顧言在鐘樓背面。手機在墜落物上。23:00 前不可能再介入。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）然後他會轉向星棠。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊盡頭是一扇鐵門。韓越從口袋裡掏出一段鐵絲——不是開鎖工具，是舞台組用來臨時固定門閂的。他把鐵絲插進門閂的縫隙裡，扭了一下。門開了。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "舊器材倉。裡面很暗。堆滿了折疊桌椅、舞台燈架、捲起來的紅地毯。空氣裡有灰塵和潤滑油的味道。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "穿過器材倉，另一頭的門通向禮堂側台卸貨口。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "到這裡。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "再往前是側台。有攝影機。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你不能被看見。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "知道。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你等。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "我去確認星棠的位置。再回來接你。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越看了他一眼。雨從他下巴滴下來。他的嘴動了一下，像是想說什麼，但最後什麼都沒說。他轉身，推開卸貨口的門，走進了禮堂側台的燈光裡。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門關上了。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在舊器材倉裡。黑暗。灰塵。潤滑油的味道。雨聲從外面傳進來，隔著鐵皮牆壁，變成了一種悶悶的、像心跳一樣的節奏。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）假死成功。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔現在應該在判斷。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他會等。不會立刻確認。因為維修庭院封閉、暴雨積水、閉幕直播只剩三十分鐘。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他會把確認延後。把優先順序轉向星棠。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）三十八分鐘。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）從 22:22 到 23:00。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這三十八分鐘裡——他以為我死了。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這三十八分鐘裡——我在他背後。", background: Background.Chapter_8_Ch8_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他靠在一堆捲起來的紅地毯上。閉上眼睛。雨聲在鐵皮牆壁外面響著。像呼吸。像倒數。像一個已經開始但還沒有到終點的過程。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在等韓越回來。", background: Background.Chapter_8_Ch8_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在等 23:00。", background: Background.Chapter_8_Ch8_Act13_S1 },
];
